/* ============================ §2 Gram–Schmidt widget ============================ */
(function(){
  const svg = $('#gs-svg'), step = $('#gs-step'), stepOut = $('#gs-step-out'),
        out = $('#gs-out'), reset = $('#gs-reset');
  const W=520, H=360, cx=W/2, cy=H/2, S=55;
  // vector data (in math coords, y up)
  let vs = [ {x:2.6,y:0.6,color:'var(--blue)',lbl:'v₁'},
             {x:0.9,y:2.3,color:'var(--green)',lbl:'v₂'},
             {x:-1.6,y:1.6,color:'var(--pink)',lbl:'v₃'} ];

  function toPix(v){ return [cx+v.x*S, cy-v.y*S]; }
  function fromPix(p){ return {x:(p[0]-cx)/S, y:(cy-p[1])/S}; }

  function drawAxes(){
    svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
    for(let k=-4;k<=4;k++){
      if(k===0) continue;
      svg.appendChild(SVG('line',{x1:cx+k*S,y1:cy-3,x2:cx+k*S,y2:cy+3,stroke:'var(--mute)'}));
      svg.appendChild(SVG('line',{x1:cx-3,y1:cy-k*S,x2:cx+3,y2:cy-k*S,stroke:'var(--mute)'}));
    }
  }
  function arrow(from, to, color, label, width=2){
    drawArrow(svg, from, to, {color, width, markerId:'gs-'+color.replace(/[^a-z]/g,''), pad1:0, pad2:2});
    if(label){
      const t = SVG('text',{x:to[0]+8, y:to[1]-4, 'font-size':13, fill:color,'font-weight':600});
      t.textContent = label; svg.appendChild(t);
    }
  }

  function dot(a,b){ return a.x*b.x + a.y*b.y; }
  function sub(a,b){ return {x:a.x-b.x, y:a.y-b.y}; }
  function scale(a,t){ return {x:a.x*t, y:a.y*t}; }
  function norm(a){ return Math.hypot(a.x,a.y); }

  function render(){
    svg.innerHTML = '';
    drawAxes();
    const s = parseInt(step.value);
    // draw input vectors (dim)
    for(const v of vs){
      arrow([cx,cy], toPix(v), v.color, v.lbl, 1.5);
    }
    // Gram–Schmidt (2D, so e3 will be zero)
    const v1=vs[0], v2=vs[1], v3=vs[2];
    const n1 = norm(v1);
    const e1 = n1>1e-9 ? scale(v1,1/n1) : {x:0,y:0};
    const u2 = sub(v2, scale(e1, dot(v2,e1)));
    const n2 = norm(u2);
    const e2 = n2>1e-9 ? scale(u2,1/n2) : {x:0,y:0};
    const u3 = sub(sub(v3, scale(e1, dot(v3,e1))), scale(e2, dot(v3,e2)));
    const n3 = norm(u3);
    const e3 = n3>1e-9 ? scale(u3,1/n3) : {x:0,y:0};

    let lines = [];
    if(s>=1){ arrow([cx,cy], toPix(e1), 'var(--yellow)', 'e₁'); lines.push(`e₁ = v₁/‖v₁‖ = (${e1.x.toFixed(2)}, ${e1.y.toFixed(2)})`); }
    if(s>=2){
      // show the projection of v2 onto span(e1) as a dashed vector
      const proj2 = scale(e1, dot(v2,e1));
      drawArrow(svg, [cx,cy], toPix(proj2), {color:'var(--mute)', dash:'4 3', width:1, markerId:'gs-proj', pad1:0, pad2:0});
      arrow([cx,cy], toPix(e2), 'var(--yellow)', 'e₂');
      lines.push(`e₂ = (v₂ − ⟨v₂,e₁⟩ e₁) / ‖·‖ = (${e2.x.toFixed(2)}, ${e2.y.toFixed(2)})`);
    }
    if(s>=3){
      lines.push(`e₃ would be (v₃ − ⟨v₃,e₁⟩e₁ − ⟨v₃,e₂⟩e₂)/‖·‖`);
      if(n3 < 1e-6){
        lines.push(`‖u₃‖ = ${n3.toExponential(2)}  →  v₃ lies in span(v₁,v₂) (forced in 2D); e₃ = 0.`);
      } else {
        lines.push(`but we're in ℝ²:  u₃ = (${u3.x.toFixed(3)}, ${u3.y.toFixed(3)}) rounds to zero within the span.`);
      }
    }
    stepOut.textContent = `step ${s} / 3`;
    out.textContent = lines.join('\n') || 'slide the step to 1 to orthogonalize.';

    // draggable handles
    vs.forEach((v,i)=>{
      const [px,py] = toPix(v);
      const h = SVG('circle',{cx:px,cy:py,r:7,fill:v.color,stroke:'#fff','stroke-width':1.5, style:'cursor:grab'});
      h.addEventListener('pointerdown', ev=>{
        ev.preventDefault();
        h.setPointerCapture(ev.pointerId);
        const move = e=>{
          const rect = svg.getBoundingClientRect();
          const sx = (e.clientX-rect.left)*W/rect.width;
          const sy = (e.clientY-rect.top)*H/rect.height;
          const p = fromPix([sx,sy]);
          vs[i].x = Math.max(-4,Math.min(4,p.x));
          vs[i].y = Math.max(-3,Math.min(3,p.y));
          render();
        };
        h.addEventListener('pointermove', move);
        h.addEventListener('pointerup', ()=>{ h.removeEventListener('pointermove', move); }, {once:true});
      });
      svg.appendChild(h);
    });
  }
  step.addEventListener('input', render);
  reset.addEventListener('click', ()=>{
    vs = [ {x:2.6,y:0.6,color:'var(--blue)',lbl:'v₁'},
           {x:0.9,y:2.3,color:'var(--green)',lbl:'v₂'},
           {x:-1.6,y:1.6,color:'var(--pink)',lbl:'v₃'} ];
    render();
  });
  render();
})();

/* ============================ §2 projection in ℝ³ widget ============================ */
(function(){
  const svg = $('#proj-svg'), sel = $('#proj-sub'), out = $('#proj-out');
  const W=560, H=380, cx=W/2, cy=H*0.58;
  // axonometric projection: ℝ³ → plane
  function proj3(p){
    const [x,y,z] = p;
    // standard isometric-ish
    const a = Math.PI/6;
    const sx = x*Math.cos(a) - y*Math.cos(a);
    const sy = -(z - x*Math.sin(a) - y*Math.sin(a));
    return [cx + sx*50, cy + sy*50];
  }
  function sub3(a,b){ return [a[0]-b[0], a[1]-b[1], a[2]-b[2]]; }
  function add3(a,b){ return [a[0]+b[0], a[1]+b[1], a[2]+b[2]]; }
  function sc3(a,t){ return [a[0]*t, a[1]*t, a[2]*t]; }
  function dot3(a,b){ return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
  function nrm3(a){ return Math.sqrt(dot3(a,a)); }

  let v = [1.8, 1.2, 2.0];

  function projectOnto(kind, v){
    if(kind==='L1'){
      // span(e1)
      return [v[0], 0, 0];
    }
    if(kind==='P12'){
      return [v[0], v[1], 0];
    }
    // plane x+y+z=0, normal n=(1,1,1)/√3
    const n = [1/Math.sqrt(3), 1/Math.sqrt(3), 1/Math.sqrt(3)];
    const c = dot3(v,n);
    return sub3(v, sc3(n, c));
  }

  function drawAxes(){
    const O = proj3([0,0,0]);
    const ex = proj3([3,0,0]), ey = proj3([0,3,0]), ez = proj3([0,0,3]);
    drawArrow(svg, O, ex, {color:'var(--mute)', markerId:'p3-x', width:1, pad1:0, pad2:2});
    drawArrow(svg, O, ey, {color:'var(--mute)', markerId:'p3-y', width:1, pad1:0, pad2:2});
    drawArrow(svg, O, ez, {color:'var(--mute)', markerId:'p3-z', width:1, pad1:0, pad2:2});
    for(const [p,lbl] of [[ex,'x'],[ey,'y'],[ez,'z']]){
      const t = SVG('text',{x:p[0]+6, y:p[1]+4,'font-size':12, fill:'var(--mute)'});
      t.textContent = lbl; svg.appendChild(t);
    }
  }

  function drawSubspace(kind){
    if(kind==='L1'){
      const a = proj3([-3,0,0]), b = proj3([3,0,0]);
      svg.appendChild(SVG('line',{x1:a[0],y1:a[1],x2:b[0],y2:b[1],
        stroke:'var(--cyan)','stroke-width':2,'stroke-dasharray':'5 4'}));
    } else if(kind==='P12'){
      // parallelogram corners
      const pts = [[-2.5,-2.5,0],[2.5,-2.5,0],[2.5,2.5,0],[-2.5,2.5,0]];
      const d = pts.map(p=>proj3(p)).map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ')+' Z';
      svg.appendChild(SVG('path',{d, fill:'var(--cyan)', 'fill-opacity':0.12, stroke:'var(--cyan)','stroke-width':1}));
    } else {
      // plane x+y+z=0; parameterize with u=(1,-1,0)/√2, w=(1,1,-2)/√6
      const u=[1/Math.sqrt(2),-1/Math.sqrt(2),0], w=[1/Math.sqrt(6),1/Math.sqrt(6),-2/Math.sqrt(6)];
      const pts=[];
      for(const s of [-2.5,2.5]) for(const t of [-2.5,2.5]){
        pts.push([u[0]*s+w[0]*t, u[1]*s+w[1]*t, u[2]*s+w[2]*t]);
      }
      // reorder to a proper quad
      const quad=[pts[0],pts[1],pts[3],pts[2]];
      const d = quad.map(p=>proj3(p)).map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ')+' Z';
      svg.appendChild(SVG('path',{d, fill:'var(--cyan)', 'fill-opacity':0.12, stroke:'var(--cyan)','stroke-width':1}));
    }
  }

  function render(){
    svg.innerHTML = '';
    drawAxes();
    const kind = sel.value;
    drawSubspace(kind);

    const O = proj3([0,0,0]);
    const Vp = proj3(v);
    const Pv = projectOnto(kind, v);
    const r  = sub3(v,Pv);
    const PvP = proj3(Pv);

    // v (blue)
    drawArrow(svg, O, Vp, {color:'var(--blue)', width:2.2, markerId:'p3-v', pad1:0, pad2:4});
    const tv = SVG('text',{x:Vp[0]+8,y:Vp[1]-4,'font-size':13,fill:'var(--blue)','font-weight':600});
    tv.textContent='v'; svg.appendChild(tv);
    // Pv (yellow)
    drawArrow(svg, O, PvP, {color:'var(--yellow)', width:2.2, markerId:'p3-pv', pad1:0, pad2:4});
    const tp = SVG('text',{x:PvP[0]+8,y:PvP[1]+14,'font-size':13,fill:'var(--yellow)','font-weight':600});
    tp.textContent='Pv'; svg.appendChild(tp);
    // residual (pink) from Pv to v
    drawArrow(svg, PvP, Vp, {color:'var(--pink)', width:2, markerId:'p3-r', pad1:0, pad2:4, dash:'4 3'});
    const tr = SVG('text',{x:(PvP[0]+Vp[0])/2+8,y:(PvP[1]+Vp[1])/2,'font-size':12,fill:'var(--pink)'});
    tr.textContent='v − Pv'; svg.appendChild(tr);

    // handle on v
    const h = SVG('circle',{cx:Vp[0],cy:Vp[1],r:7,fill:'var(--blue)',stroke:'#fff','stroke-width':1.5, style:'cursor:grab'});
    h.addEventListener('pointerdown', ev=>{
      ev.preventDefault();
      h.setPointerCapture(ev.pointerId);
      const startX = ev.clientX, startY = ev.clientY;
      const v0 = v.slice();
      const rect = svg.getBoundingClientRect();
      const move = e=>{
        const dx = (e.clientX-startX)*W/rect.width/50;
        const dy = (e.clientY-startY)*H/rect.height/50;
        // move in (x,z) plane: left/right changes x; up/down changes z
        v = [v0[0]+dx, v0[1], v0[2]-dy];
        render();
      };
      h.addEventListener('pointermove', move);
      h.addEventListener('pointerup', ()=>h.removeEventListener('pointermove', move), {once:true});
    });
    svg.appendChild(h);

    const nv=nrm3(v), npv=nrm3(Pv), nr=nrm3(r);
    out.textContent =
`v     = (${v[0].toFixed(2)}, ${v[1].toFixed(2)}, ${v[2].toFixed(2)})    ‖v‖   = ${nv.toFixed(3)}
Pv    = (${Pv[0].toFixed(2)}, ${Pv[1].toFixed(2)}, ${Pv[2].toFixed(2)})    ‖Pv‖  = ${npv.toFixed(3)}
v−Pv  = (${r[0].toFixed(2)}, ${r[1].toFixed(2)}, ${r[2].toFixed(2)})    ‖v−Pv‖= ${nr.toFixed(3)}
⟨Pv, v−Pv⟩ = ${dot3(Pv,r).toFixed(4)}    (should be 0 — orthogonality)
‖v‖² = ${(nv*nv).toFixed(3)}    vs    ‖Pv‖² + ‖v−Pv‖² = ${(npv*npv + nr*nr).toFixed(3)}  (Pythagoras)`;
  }

  sel.addEventListener('change', render);
  render();
})();

/* ============================ §2 Gram–Schmidt widget ============================ */
(function(){
  const svg = $('#gs-svg'), step = $('#gs-step'), stepOut = $('#gs-step-out'),
        out = $('#gs-out'), reset = $('#gs-reset');
  const W=520, H=360, cx=W/2, cy=H/2, S=55;
  // vector data (in math coords, y up)
  let vs = [ {x:2.6,y:0.6,color:'var(--blue)',lbl:'v₁'},
             {x:0.9,y:2.3,color:'var(--green)',lbl:'v₂'},
             {x:-1.6,y:1.6,color:'var(--pink)',lbl:'v₃'} ];

  function toPix(v){ return [cx+v.x*S, cy-v.y*S]; }
  function fromPix(p){ return {x:(p[0]-cx)/S, y:(cy-p[1])/S}; }

  function drawAxes(){
    svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
    for(let k=-4;k<=4;k++){
      if(k===0) continue;
      svg.appendChild(SVG('line',{x1:cx+k*S,y1:cy-3,x2:cx+k*S,y2:cy+3,stroke:'var(--mute)'}));
      svg.appendChild(SVG('line',{x1:cx-3,y1:cy-k*S,x2:cx+3,y2:cy-k*S,stroke:'var(--mute)'}));
    }
  }
  function arrow(from, to, color, label, width=2){
    drawArrow(svg, from, to, {color, width, markerId:'gs-'+color.replace(/[^a-z]/g,''), pad1:0, pad2:2});
    if(label){
      const t = SVG('text',{x:to[0]+8, y:to[1]-4, 'font-size':13, fill:color,'font-weight':600});
      t.textContent = label; svg.appendChild(t);
    }
  }

  function dot(a,b){ return a.x*b.x + a.y*b.y; }
  function sub(a,b){ return {x:a.x-b.x, y:a.y-b.y}; }
  function scale(a,t){ return {x:a.x*t, y:a.y*t}; }
  function norm(a){ return Math.hypot(a.x,a.y); }

  function render(){
    svg.innerHTML = '';
    drawAxes();
    const s = parseInt(step.value);
    // draw input vectors (dim)
    for(const v of vs){
      arrow([cx,cy], toPix(v), v.color, v.lbl, 1.5);
    }
    // Gram–Schmidt (2D, so e3 will be zero)
    const v1=vs[0], v2=vs[1], v3=vs[2];
    const n1 = norm(v1);
    const e1 = n1>1e-9 ? scale(v1,1/n1) : {x:0,y:0};
    const u2 = sub(v2, scale(e1, dot(v2,e1)));
    const n2 = norm(u2);
    const e2 = n2>1e-9 ? scale(u2,1/n2) : {x:0,y:0};
    const u3 = sub(sub(v3, scale(e1, dot(v3,e1))), scale(e2, dot(v3,e2)));
    const n3 = norm(u3);
    const e3 = n3>1e-9 ? scale(u3,1/n3) : {x:0,y:0};

    let lines = [];
    if(s>=1){ arrow([cx,cy], toPix(e1), 'var(--yellow)', 'e₁'); lines.push(`e₁ = v₁/‖v₁‖ = (${e1.x.toFixed(2)}, ${e1.y.toFixed(2)})`); }
    if(s>=2){
      // show the projection of v2 onto span(e1) as a dashed vector
      const proj2 = scale(e1, dot(v2,e1));
      drawArrow(svg, [cx,cy], toPix(proj2), {color:'var(--mute)', dash:'4 3', width:1, markerId:'gs-proj', pad1:0, pad2:0});
      arrow([cx,cy], toPix(e2), 'var(--yellow)', 'e₂');
      lines.push(`e₂ = (v₂ − ⟨v₂,e₁⟩ e₁) / ‖·‖ = (${e2.x.toFixed(2)}, ${e2.y.toFixed(2)})`);
    }
    if(s>=3){
      lines.push(`e₃ would be (v₃ − ⟨v₃,e₁⟩e₁ − ⟨v₃,e₂⟩e₂)/‖·‖`);
      if(n3 < 1e-6){
        lines.push(`‖u₃‖ = ${n3.toExponential(2)}  →  v₃ lies in span(v₁,v₂) (forced in 2D); e₃ = 0.`);
      } else {
        lines.push(`but we're in ℝ²:  u₃ = (${u3.x.toFixed(3)}, ${u3.y.toFixed(3)}) rounds to zero within the span.`);
      }
    }
    stepOut.textContent = `step ${s} / 3`;
    out.textContent = lines.join('\n') || 'slide the step to 1 to orthogonalize.';

    // draggable handles
    vs.forEach((v,i)=>{
      const [px,py] = toPix(v);
      const h = SVG('circle',{cx:px,cy:py,r:7,fill:v.color,stroke:'#fff','stroke-width':1.5, style:'cursor:grab'});
      h.addEventListener('pointerdown', ev=>{
        ev.preventDefault();
        h.setPointerCapture(ev.pointerId);
        const move = e=>{
          const rect = svg.getBoundingClientRect();
          const sx = (e.clientX-rect.left)*W/rect.width;
          const sy = (e.clientY-rect.top)*H/rect.height;
          const p = fromPix([sx,sy]);
          vs[i].x = Math.max(-4,Math.min(4,p.x));
          vs[i].y = Math.max(-3,Math.min(3,p.y));
          render();
        };
        h.addEventListener('pointermove', move);
        h.addEventListener('pointerup', ()=>{ h.removeEventListener('pointermove', move); }, {once:true});
      });
      svg.appendChild(h);
    });
  }
  step.addEventListener('input', render);
  reset.addEventListener('click', ()=>{
    vs = [ {x:2.6,y:0.6,color:'var(--blue)',lbl:'v₁'},
           {x:0.9,y:2.3,color:'var(--green)',lbl:'v₂'},
           {x:-1.6,y:1.6,color:'var(--pink)',lbl:'v₃'} ];
    render();
  });
  render();
})();

/* ============================ §2 projection in ℝ³ widget ============================ */
(function(){
  const svg = $('#proj-svg'), sel = $('#proj-sub'), out = $('#proj-out');
  const W=560, H=380, cx=W/2, cy=H*0.58;
  // axonometric projection: ℝ³ → plane
  function proj3(p){
    const [x,y,z] = p;
    // standard isometric-ish
    const a = Math.PI/6;
    const sx = x*Math.cos(a) - y*Math.cos(a);
    const sy = -(z - x*Math.sin(a) - y*Math.sin(a));
    return [cx + sx*50, cy + sy*50];
  }
  function sub3(a,b){ return [a[0]-b[0], a[1]-b[1], a[2]-b[2]]; }
  function add3(a,b){ return [a[0]+b[0], a[1]+b[1], a[2]+b[2]]; }
  function sc3(a,t){ return [a[0]*t, a[1]*t, a[2]*t]; }
  function dot3(a,b){ return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
  function nrm3(a){ return Math.sqrt(dot3(a,a)); }

  let v = [1.8, 1.2, 2.0];

  function projectOnto(kind, v){
    if(kind==='L1'){
      // span(e1)
      return [v[0], 0, 0];
    }
    if(kind==='P12'){
      return [v[0], v[1], 0];
    }
    // plane x+y+z=0, normal n=(1,1,1)/√3
    const n = [1/Math.sqrt(3), 1/Math.sqrt(3), 1/Math.sqrt(3)];
    const c = dot3(v,n);
    return sub3(v, sc3(n, c));
  }

  function drawAxes(){
    const O = proj3([0,0,0]);
    const ex = proj3([3,0,0]), ey = proj3([0,3,0]), ez = proj3([0,0,3]);
    drawArrow(svg, O, ex, {color:'var(--mute)', markerId:'p3-x', width:1, pad1:0, pad2:2});
    drawArrow(svg, O, ey, {color:'var(--mute)', markerId:'p3-y', width:1, pad1:0, pad2:2});
    drawArrow(svg, O, ez, {color:'var(--mute)', markerId:'p3-z', width:1, pad1:0, pad2:2});
    for(const [p,lbl] of [[ex,'x'],[ey,'y'],[ez,'z']]){
      const t = SVG('text',{x:p[0]+6, y:p[1]+4,'font-size':12, fill:'var(--mute)'});
      t.textContent = lbl; svg.appendChild(t);
    }
  }

  function drawSubspace(kind){
    if(kind==='L1'){
      const a = proj3([-3,0,0]), b = proj3([3,0,0]);
      svg.appendChild(SVG('line',{x1:a[0],y1:a[1],x2:b[0],y2:b[1],
        stroke:'var(--cyan)','stroke-width':2,'stroke-dasharray':'5 4'}));
    } else if(kind==='P12'){
      // parallelogram corners
      const pts = [[-2.5,-2.5,0],[2.5,-2.5,0],[2.5,2.5,0],[-2.5,2.5,0]];
      const d = pts.map(p=>proj3(p)).map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ')+' Z';
      svg.appendChild(SVG('path',{d, fill:'var(--cyan)', 'fill-opacity':0.12, stroke:'var(--cyan)','stroke-width':1}));
    } else {
      // plane x+y+z=0; parameterize with u=(1,-1,0)/√2, w=(1,1,-2)/√6
      const u=[1/Math.sqrt(2),-1/Math.sqrt(2),0], w=[1/Math.sqrt(6),1/Math.sqrt(6),-2/Math.sqrt(6)];
      const pts=[];
      for(const s of [-2.5,2.5]) for(const t of [-2.5,2.5]){
        pts.push([u[0]*s+w[0]*t, u[1]*s+w[1]*t, u[2]*s+w[2]*t]);
      }
      // reorder to a proper quad
      const quad=[pts[0],pts[1],pts[3],pts[2]];
      const d = quad.map(p=>proj3(p)).map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ')+' Z';
      svg.appendChild(SVG('path',{d, fill:'var(--cyan)', 'fill-opacity':0.12, stroke:'var(--cyan)','stroke-width':1}));
    }
  }

  function render(){
    svg.innerHTML = '';
    drawAxes();
    const kind = sel.value;
    drawSubspace(kind);

    const O = proj3([0,0,0]);
    const Vp = proj3(v);
    const Pv = projectOnto(kind, v);
    const r  = sub3(v,Pv);
    const PvP = proj3(Pv);

    // v (blue)
    drawArrow(svg, O, Vp, {color:'var(--blue)', width:2.2, markerId:'p3-v', pad1:0, pad2:4});
    const tv = SVG('text',{x:Vp[0]+8,y:Vp[1]-4,'font-size':13,fill:'var(--blue)','font-weight':600});
    tv.textContent='v'; svg.appendChild(tv);
    // Pv (yellow)
    drawArrow(svg, O, PvP, {color:'var(--yellow)', width:2.2, markerId:'p3-pv', pad1:0, pad2:4});
    const tp = SVG('text',{x:PvP[0]+8,y:PvP[1]+14,'font-size':13,fill:'var(--yellow)','font-weight':600});
    tp.textContent='Pv'; svg.appendChild(tp);
    // residual (pink) from Pv to v
    drawArrow(svg, PvP, Vp, {color:'var(--pink)', width:2, markerId:'p3-r', pad1:0, pad2:4, dash:'4 3'});
    const tr = SVG('text',{x:(PvP[0]+Vp[0])/2+8,y:(PvP[1]+Vp[1])/2,'font-size':12,fill:'var(--pink)'});
    tr.textContent='v − Pv'; svg.appendChild(tr);

    // handle on v
    const h = SVG('circle',{cx:Vp[0],cy:Vp[1],r:7,fill:'var(--blue)',stroke:'#fff','stroke-width':1.5, style:'cursor:grab'});
    h.addEventListener('pointerdown', ev=>{
      ev.preventDefault();
      h.setPointerCapture(ev.pointerId);
      const startX = ev.clientX, startY = ev.clientY;
      const v0 = v.slice();
      const rect = svg.getBoundingClientRect();
      const move = e=>{
        const dx = (e.clientX-startX)*W/rect.width/50;
        const dy = (e.clientY-startY)*H/rect.height/50;
        // move in (x,z) plane: left/right changes x; up/down changes z
        v = [v0[0]+dx, v0[1], v0[2]-dy];
        render();
      };
      h.addEventListener('pointermove', move);
      h.addEventListener('pointerup', ()=>h.removeEventListener('pointermove', move), {once:true});
    });
    svg.appendChild(h);

    const nv=nrm3(v), npv=nrm3(Pv), nr=nrm3(r);
    out.textContent =
`v     = (${v[0].toFixed(2)}, ${v[1].toFixed(2)}, ${v[2].toFixed(2)})    ‖v‖   = ${nv.toFixed(3)}
Pv    = (${Pv[0].toFixed(2)}, ${Pv[1].toFixed(2)}, ${Pv[2].toFixed(2)})    ‖Pv‖  = ${npv.toFixed(3)}
v−Pv  = (${r[0].toFixed(2)}, ${r[1].toFixed(2)}, ${r[2].toFixed(2)})    ‖v−Pv‖= ${nr.toFixed(3)}
⟨Pv, v−Pv⟩ = ${dot3(Pv,r).toFixed(4)}    (should be 0 — orthogonality)
‖v‖² = ${(nv*nv).toFixed(3)}    vs    ‖Pv‖² + ‖v−Pv‖² = ${(npv*npv + nr*nr).toFixed(3)}  (Pythagoras)`;
  }

  sel.addEventListener('change', render);
  render();
})();

