        out = $('#opn-out');
  const W=560, H=360, cx=W/2, cy=H/2, R=90;

  function svd2(A){
    // compute SVD of 2x2 matrix: returns {sigma: [s1,s2], angles}
    const [a,b,c,d] = [A[0][0],A[0][1],A[1][0],A[1][1]];
    // compute eigenvalues of A^T A
    const t11 = a*a + c*c, t22 = b*b + d*d, t12 = a*b + c*d;
    const tr = t11 + t22;
    const det = t11*t22 - t12*t12;
    const disc = Math.max(0, tr*tr/4 - det);
    const lam1 = tr/2 + Math.sqrt(disc);
    const lam2 = tr/2 - Math.sqrt(disc);
    return {s1: Math.sqrt(Math.max(0,lam1)), s2: Math.sqrt(Math.max(0,lam2))};
  }

  function render(){
    svg.innerHTML='';
    const a=parseFloat(aS.value), b=parseFloat(bS.value), c=parseFloat(cS.value), d=parseFloat(dS.value);
