      const th = 2*Math.PI*i/Npts;
      const x = Math.cos(th), y = Math.sin(th);
      inpts.push([cx + x*R, cy - y*R]);
      const Tx = a*x + b*y, Ty = c*x + d*y;
      outpts.push([cx + Tx*R, cy - Ty*R]);
