    const indash = inpts.map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ') + ' Z';
    svg.appendChild(SVG('path',{d:indash, fill:'none', stroke:'var(--cyan)', 'stroke-width':1.2, 'stroke-dasharray':'4 3'}));
