    if(op === 'diag-1n'){
      // σ = {0} ∪ {1/n : n≥1}. Point spectrum = {1/n : n≥1}; σ_c = σ_r = ∅ for nonzero; 0 is in σ but not eigenvalue.
      if(Math.abs(im) > 1e-3) return {part:'resolvent', note:'Im λ ≠ 0 ⇒ resolvent'};
      // check if re = 1/n for some small n
      for(let n=1;n<=50;n++){
        if(Math.abs(re - 1/n) < 0.02) return {part:'point', note:`λ ≈ 1/${n} ⇒ eigenvalue (eigenvector e_${n})`};
      }
      if(Math.abs(re) < 0.02) return {part:'continuous', note:'λ ≈ 0 ⇒ accumulation point of σ_p, lies in σ but NOT an eigenvalue (continuous part)'};
      return {part:'resolvent', note:'not 1/n and not 0 ⇒ resolvent'};
    }
    return {part:'resolvent', note:'?'};
  }

  function drawSpectrum(op){
    // draw the spectrum as colored region / points
    const sc = (z) => [cx + z[0]*R, cy - z[1]*R];
    // always axes
    svg.appendChild(SVG('line',{x1:30,y1:cy,x2:W-30,y2:cy,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
