    const ty = SVG('text',{x:cx+6,y:cy-R+4,'font-size':11,fill:'var(--mute)'}); ty.textContent='i'; svg.appendChild(ty);

    if(op==='shift-R' || op==='shift-L'){
      // closed disk colored by parts
      const rr = R;
      // residual (open disk) — for right shift
      if(op === 'shift-R'){
        svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:rr,fill:'var(--pink)','fill-opacity':0.15, stroke:'none'}));
      } else {
        svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:rr,fill:'var(--yellow)','fill-opacity':0.18, stroke:'none'}));
      }
