      svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:rr,fill:'none',stroke:'var(--cyan)','stroke-width':2.5}));
    } else if(op==='mult-x'){
      // interval [0,1] on real axis
      svg.appendChild(SVG('line',{x1:cx, y1:cy, x2:cx+R, y2:cy, stroke:'var(--cyan)','stroke-width':4}));
    } else if(op==='sigma-z'){
      // two points at ±1
      svg.appendChild(SVG('circle',{cx:cx+R, cy:cy, r:5, fill:'var(--yellow)'}));
      svg.appendChild(SVG('circle',{cx:cx-R, cy:cy, r:5, fill:'var(--yellow)'}));
    } else if(op==='diag-1n'){
      // 0 (cyan, accumulation) and 1/n (yellow point spectrum)
      svg.appendChild(SVG('circle',{cx:cx, cy:cy, r:5, fill:'var(--cyan)'}));
      for(let n=1;n<=30;n++){
        svg.appendChild(SVG('circle',{cx:cx+R/n, cy:cy, r:Math.max(1.5, 4-n*0.1), fill:'var(--yellow)'}));
      }
    }
  }

  function drawLambda(re, im){
    const px = cx + re*R, py = cy - im*R;
