`operator: ${opSel.options[opSel.selectedIndex].text.replace(/<[^>]+>/g,'')}
λ = ${re.toFixed(2)}${im>=0?' + ':' − '}${Math.abs(im).toFixed(2)}i

classification: λ ∈ ${res.part.toUpperCase()}
${res.note}`;
