/* ============================ §7 Fourier-series widget ============================ */
(function(){
  const svg = $('#fs-svg'), tgt = $('#fs-tgt'), N = $('#fs-N'), NOut = $('#fs-N-out'), out = $('#fs-out');
  const W=560, H=300, padL=40, padR=20, padT=20, padB=30;
  const xmin=-Math.PI, xmax=Math.PI;
  function f(name, x){
    if(name==='step') return x>0 ? 1 : (x<0 ? -1 : 0);
    if(name==='tri')  return 1 - Math.abs(x)/Math.PI * 2;
    if(name==='saw')  return x/Math.PI;
    return 0;
  }

  // Fourier coefficients via numerical integration (fine grid)
  const G = 1024;
  function coeffs(name, N){
    // real Fourier: a_0/2 + sum a_k cos(kx) + b_k sin(kx)
    const a = new Array(N+1).fill(0);
    const b = new Array(N+1).fill(0);
    const dx = 2*Math.PI/G;
    for(let i=0;i<G;i++){
      const x = -Math.PI + (i+0.5)*dx;
      const y = f(name, x);
      a[0] += y*dx;
      for(let k=1;k<=N;k++){
        a[k] += y*Math.cos(k*x)*dx;
        b[k] += y*Math.sin(k*x)*dx;
      }
    }
    for(let k=0;k<=N;k++){ a[k] /= Math.PI; b[k] /= Math.PI; }
    return {a,b};
  }
  function SN(name, N, x){
    const {a,b} = coeffs(name, N);
    let s = a[0]/2;
    for(let k=1;k<=N;k++) s += a[k]*Math.cos(k*x) + b[k]*Math.sin(k*x);
    return s;
  }
  // Parseval-based L^2 error:
  // ||f||^2 = π (a_0^2/2 + Σ (a_k^2 + b_k^2))  [using our normalization a_k = (1/π)∫ f cos(kx)]
  // Actually with our conventions:
  //   f ~ a_0/2 + Σ a_k cos + b_k sin
  //   ||f||_L2^2 = π ( a_0^2/2 + Σ (a_k^2 + b_k^2) )
  // ||f - S_N||^2 = π Σ_{k>N} (a_k^2 + b_k^2)
  // We estimate via a larger set of coefficients.

  function L2error(name, N){
    const {a,b} = coeffs(name, Math.max(80, N+50));
    let tail = 0;
    for(let k=N+1;k<a.length;k++) tail += a[k]*a[k] + b[k]*b[k];
    return Math.sqrt(Math.PI*tail);
  }

  function render(){
    svg.innerHTML='';
    const name = tgt.value;
    const n = parseInt(N.value);
    NOut.textContent = 'N = '+n;

    const sx = x => padL + (x-xmin)/(xmax-xmin)*(W-padL-padR);
    const sy = y => padT + (1.6 - y)/3.2 *(H-padT-padB);

    // axes
    svg.appendChild(SVG('line',{x1:padL,y1:sy(0),x2:W-padR,y2:sy(0),stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:sx(0),y1:padT,x2:sx(0),y2:H-padB,stroke:'var(--line)'}));
    for(const v of [-Math.PI,-Math.PI/2,Math.PI/2,Math.PI]){
      const x = sx(v);
      svg.appendChild(SVG('line',{x1:x,y1:sy(0)-3,x2:x,y2:sy(0)+3,stroke:'var(--mute)'}));
    }
    for(const v of [-1,1]){
      const y = sy(v);
      svg.appendChild(SVG('line',{x1:sx(0)-3,y1:y,x2:sx(0)+3,y2:y,stroke:'var(--mute)'}));
    }

    // target f — piecewise to handle the jump cleanly
    let tpts = [];
    const M = 800;
    for(let i=0;i<=M;i++){
      const x = xmin + i*(xmax-xmin)/M;
      tpts.push([sx(x), sy(f(name,x))]);
    }
    const td = tpts.map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ');
    svg.appendChild(SVG('path',{d:td, fill:'none', stroke:'var(--mute)', 'stroke-width':1.5, 'stroke-dasharray':'4 3'}));

    // S_N f
    let spts = [];
    for(let i=0;i<=M;i++){
      const x = xmin + i*(xmax-xmin)/M;
      spts.push([sx(x), sy(SN(name, n, x))]);
    }
    const sd = spts.map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ');
    svg.appendChild(SVG('path',{d:sd, fill:'none', stroke:'var(--yellow)', 'stroke-width':2}));

    // legend
    const lg1 = SVG('text',{x:W-padR-4,y:padT+14,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
    lg1.textContent = 'target f(x)'; svg.appendChild(lg1);
    const lg2 = SVG('text',{x:W-padR-4,y:padT+30,'text-anchor':'end','font-size':12,fill:'var(--yellow)'});
    lg2.textContent = `S_${n} f(x)`; svg.appendChild(lg2);

    const err = L2error(name, n);
    out.textContent =
`target: ${name},  N = ${n}
‖f − S_N f‖_{L²[-π,π]}  ≈ ${err.toFixed(4)}
(decreases monotonically as N→∞ for any f ∈ L²; Parseval guarantees → 0.)
Pointwise near jumps: Gibbs overshoot ≈ 9% of the jump persists for every N — but it is localized to a shrinking window, so L² error still → 0.`;
  }

  tgt.addEventListener('change', render);
  N.addEventListener('input', render);
  render();
})();

