  const svg = $('#delta-svg'), sS = $('#delta-sigma'), sO = $('#delta-sigma-out'),
        phiSel = $('#delta-phi'), out = $('#delta-out');
  const W=560, H=300, padL=40, padR=20, padT=20, padB=30;
  const xmin=-2.5, xmax=2.5;

  function phi(name, x){
    if(name==='bump') return Math.abs(x) < 2 ? Math.exp(-x*x) : 0;
    if(name==='cos')  return Math.abs(x) < 2 ? Math.cos(x) : 0;
    if(name==='quad') return Math.abs(x) < Math.sqrt(2) ? (2 - x*x) : 0;
    if(name==='shifted') return Math.abs(x-1) < 2 ? Math.exp(-(x-1)*(x-1)) : 0;
    return 0;
  }
  function phiAt0(name){ return phi(name, 0); }

  function gauss(x, sigma){
    return Math.exp(-x*x/(2*sigma*sigma)) / (Math.sqrt(2*Math.PI)*sigma);
  }

  function render(){
    svg.innerHTML='';
    const sigma = parseFloat(sS.value);
    sO.textContent = `σ = ${sigma.toFixed(2)}`;
    const name = phiSel.value;

    // scale: y from -0.2 to max(3, 1/sigma)
    const ymax = Math.max(3, 1/(Math.sqrt(2*Math.PI)*sigma) + 0.4);
    const ymin = -0.4;
    const sx = x => padL + (x-xmin)/(xmax-xmin)*(W-padL-padR);
    const sy = y => padT + (ymax - y)/(ymax-ymin)*(H-padT-padB);

    // axes
    svg.appendChild(SVG('line',{x1:padL,y1:sy(0),x2:W-padR,y2:sy(0),stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:sx(0),y1:padT,x2:sx(0),y2:H-padB,stroke:'var(--line)'}));

    // gaussian f_sigma
    const M=400;
    let gpts=[], ppts=[];
    for(let i=0;i<=M;i++){
      const x = xmin + i*(xmax-xmin)/M;
      gpts.push([sx(x), sy(gauss(x,sigma))]);
      ppts.push([sx(x), sy(phi(name,x))]);
    }
    const gd = gpts.map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ');
    svg.appendChild(SVG('path',{d:gd, fill:'var(--yellow)', 'fill-opacity':0.2, stroke:'var(--yellow)','stroke-width':2}));
    const pd = ppts.map((p,i)=>`${i===0?'M':'L'}${p[0]} ${p[1]}`).join(' ');
    svg.appendChild(SVG('path',{d:pd, fill:'none', stroke:'var(--cyan)','stroke-width':2}));

    // pairing: approximate ∫ f_σ φ
    const G=2000;
    let integral = 0;
    const dx = (xmax-xmin)/G;
    for(let i=0;i<G;i++){
      const x = xmin + (i+0.5)*dx;
      integral += gauss(x,sigma)*phi(name,x)*dx;
    }
    // also ∫ f_σ = 1 (within the cutoff; it will be slightly <1 since we cut at ±2.5)
    let mass = 0;
    for(let i=0;i<G;i++){
      const x = xmin + (i+0.5)*dx;
      mass += gauss(x,sigma)*dx;
    }

    // legend
    const lg1 = SVG('text',{x:W-padR-4,y:padT+14,'text-anchor':'end','font-size':12,fill:'var(--yellow)'});
    lg1.textContent = `f_σ (Gaussian, σ=${sigma.toFixed(2)})`; svg.appendChild(lg1);
    const lg2 = SVG('text',{x:W-padR-4,y:padT+30,'text-anchor':'end','font-size':12,fill:'var(--cyan)'});
    lg2.textContent = 'φ (test function)'; svg.appendChild(lg2);

    const phi0 = phiAt0(name);
    out.textContent =
`approximate δ₀ pairing: ∫ f_σ(x) φ(x) dx  ≈  ${integral.toFixed(5)}
target (exact δ₀ pairing):  ⟨δ₀, φ⟩ = φ(0)  =  ${phi0.toFixed(5)}
difference:  ${(integral - phi0).toFixed(5)}

∫ f_σ  ≈  ${mass.toFixed(4)}   (→ 1; Gaussian has unit mass, minor cutoff loss at ±2.5)

As σ → 0, ∫ f_σ φ → φ(0) for every continuous φ — this is the definition of f_σ → δ₀ in 𝒟'.
Pointwise, f_σ(0) = 1/(√(2π)σ) → ∞; away from 0, f_σ(x) → 0. The limit is NOT a function.`;
  }

  sS.addEventListener('input', render);
  phiSel.addEventListener('change', render);
  render();

